function digitsToSum(input: string): number {
  if (!input || input.length === 0) {
    throw new SyntaxError('Input must not be empty');
  }

  if (!/^\d+$/.test(input)) {
    throw new SyntaxError(`Input must contain only digits 0-9, got: ${JSON.stringify(input.slice(0, 20))}`);
  }

  let sum = 0;
  for (const char of input) {
    sum += parseInt(char, 10);
  }
  return sum;
}

export { digitsToSum };
export default digitsToSum;
